pub enum SpokeAuthMode {
    /// Mount .credentials.json from the hub container (default).
    #[default]
    Credentials,
    /// Pass ANTHROPIC_API_KEY env var.
    ApiKey,
}
pub struct ReasoningConfig {
    /// Inference provider for reasoning (reuses the embedding provider enum).
    #[serde(default)]
    pub provider: InferenceProvider,
    /// Model for reasoning tasks (e.g., "llama3.2:3b").
    pub model: String,
}
